class ShortenInstruction(dspy.Signature):
    (
        """Given an instruction that is too long, rewrite it to be more concise while preserving its meaning and intent."""
    )
    instruction = dspy.InputField(
        format=str,
        desc="An instruction that is too long and needs to be shortened.",
        prefix="INSTRUCTION:",
    )
    proposed_instruction = dspy.OutputField(
        desc="A more concise version of the instruction.",
        prefix="PROPOSED INSTRUCTION:",
    )


def _truncate_instruction(instruction, max_chars):
    """Trim ``instruction`` to fit within ``max_chars``, preferring to cut at the last sentence boundary."""
    limit = max_chars - 1
    truncated = instruction[:limit]
    last_boundary = max(truncated.rfind("."), truncated.rfind("!"), truncated.rfind("?"))
    if last_boundary != -1:
        return truncated[:last_boundary + 1] + "…"
    return truncated + "…"


